export const name = "repo";
export const version = "0.1.0";
export const description = "";

export function getIdentity() {
  return { name, version, description };
}

export function slugify(input) {
  const s = _toStr(input);
  if (!s) return "";
  // Normalize and strip diacritics
  const normalized = s.normalize("NFKD").replace(/\p{M}/gu, "");
  const lower = normalized.toLowerCase();
  // Replace non letters/numbers with hyphens, collapse and trim
  const replaced = lower.replace(/[^\p{L}\p{N}]+/gu, "-");
  return replaced.replace(/(^-|-$)/g, "").replace(/-+/g, "-");
}

export function truncate(input, maxLength, suffix = "…") {
  const s = _toStr(input);
  if (s === "") return "";
  const max = Number(maxLength);
  if (!Number.isFinite(max) || max <= 0) return "";
  if (s.length <= max) return s;
  const suf = _toStr(suffix);
  const avail = Math.max(max - suf.length, 0);
  if (avail <= 0) return suf.slice(0, max);
  let head = s.slice(0, avail).replace(/\s+$/u, "");
  const lastSpace = head.lastIndexOf(" ");
  if (lastSpace > 0) {
    head = head.slice(0, lastSpace);
  }
  return head + suf;
}

export function camelCase(input) {
  const parts = _splitWords(input);
  if (parts.length === 0) return "";
  return parts
    .map((p, i) => (i === 0 ? p.toLowerCase() : p.charAt(0).toUpperCase() + p.slice(1).toLowerCase()))
    .join("");
}

export function kebabCase(input) {
  const parts = _splitWords(input);
  if (parts.length === 0) return "";
  return parts.map((p) => p.toLowerCase()).join("-");
}

export function titleCase(input) {
  const parts = _splitWords(input);
  if (parts.length === 0) return "";
  return parts.map((p) => p.charAt(0).toUpperCase() + p.slice(1).toLowerCase()).join(" ");
}

export function wordWrap(input, width) {
  const s = _toStr(input);
  if (s === "") return "";
  const w = Number(width);
  if (!Number.isFinite(w) || w <= 0) return s;

  const words = s.trim().split(/\s+/u).filter(Boolean);
  const lines = [];
  let line = "";
  for (const word of words) {
    if (!line) {
      line = word;
    } else if (line.length + 1 + word.length <= w) {
      line += " " + word;
    } else {
      lines.push(line);
      line = word;
    }
  }
  if (line) lines.push(line);
  return lines.join("\n");
}

export function stripHtml(input) {
  let s = _toStr(input);
  if (s === "") return "";
  // Remove script/style blocks first
  s = s.replace(/<script[\s\S]*?>[\s\S]*?<\/script>/gi, " ");
  s = s.replace(/<style[\s\S]*?>[\s\S]*?<\/style>/gi, " ");
  // Strip tags
  s = s.replace(/<[^>]+>/g, " ");
  // Decode basic entities
  const entities = { amp: "&", lt: "<", gt: ">", quot: '"', apos: "'", nbsp: " " };
  s = s.replace(/&([a-zA-Z]+);/g, (m, name) => entities[name] ?? m);
  s = s.replace(/&#x([0-9a-fA-F]+);/g, (m, hex) => String.fromCodePoint(parseInt(hex, 16)));
  s = s.replace(/&#([0-9]+);/g, (m, num) => String.fromCodePoint(Number(num)));
  // Collapse whitespace
  s = s.replace(/\s+/g, " ").trim();
  return s;
}

export function escapeRegex(input) {
  const s = _toStr(input);
  if (s === "") return "";
  return s.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

export function pluralize(input) {
  const w = _toStr(input);
  if (w === "") return "";
  const lower = w.toLowerCase();
  if (/(s|x|z|ch|sh)$/i.test(lower)) return w + "es";
  if (/[^aeiou]y$/i.test(lower)) return w.slice(0, -1) + "ies";
  if (/(?:fe|f)$/i.test(lower)) return w.replace(/(?:fe|f)$/i, "ves");
  return w + "s";
}

export function levenshtein(a, b) {
  const sa = _toStr(a);
  const sb = _toStr(b);
  const aArr = Array.from(sa);
  const bArr = Array.from(sb);
  const m = aArr.length;
  const n = bArr.length;
  if (m === 0) return n;
  if (n === 0) return m;
  let prev = new Array(n + 1);
  for (let j = 0; j <= n; j++) prev[j] = j;
  for (let i = 1; i <= m; i++) {
    const curr = new Array(n + 1);
    curr[0] = i;
    for (let j = 1; j <= n; j++) {
      const insertCost = curr[j - 1] + 1;
      const deleteCost = prev[j] + 1;
      const replaceCost = prev[j - 1] + (aArr[i - 1] === bArr[j - 1] ? 0 : 1);
      curr[j] = Math.min(insertCost, deleteCost, replaceCost);
    }
    prev = curr;
  }
  return prev[n];
}
